import React from 'react';
import { motion } from 'framer-motion';

export default function SummaryCard({ title, value }) {
  return (
    <motion.div
      className="card-base"
      whileHover={{ translateY: -5, boxShadow: '0 4px 16px rgba(0, 0, 0, 0.12)' }}
      transition={{ duration: 0.2 }}
    >
      <h4 className="text-gray-600 text-sm font-medium uppercase tracking-wide mb-2">
        {title}
      </h4>
      <p className="text-3xl font-bold" style={{ color: '#1F7A63' }}>
        {value}
      </p>
      <div className="mt-4 text-xs text-gray-500">
        Updated today
      </div>
    </motion.div>
  );
}
